//! Port of the upstream VictoriaMetrics `lib/uint64set` (v1.146.0).
//!
//! A fast set for `u64` values, optimized for semi-sparse values such as
//! MetricIDs generated by the storage layer. The set is organized as a
//! hierarchy: [`Set`] holds `Bucket32` entries keyed by the high 32 bits,
//! each `Bucket32` holds `Bucket16` entries keyed by the next 16 bits, and
//! each `Bucket16` stores the low 16 bits either in a small sorted-on-demand
//! pool (up to 56 items) or in a 64-Kbit bitmap.
//!
//! Deviations from the Go original:
//! - Go uses `atomic` load/store for the per-`bucket32` `hint` field so that
//!   concurrent read-mostly usage is race-free. Rust ownership makes this
//!   unnecessary: all mutating methods take `&mut self`, so `hint` is a plain
//!   `u32`.
//! - `UnionMayOwn` in Go may share (own) `a`'s buckets when profitable.
//!   With Rust ownership there is no benefit to sharing, so
//!   [`Set::union_may_own`] delegates to [`Set::union`]; observable behavior
//!   is identical (and `a` remains usable, unlike in Go).
//! - Go's `Clone` relies on copy semantics of slices plus explicit `copyTo`;
//!   the Rust port implements [`Clone`] with the same deep-copy semantics.
//! - Go pools iteration buffers in a `sync.Pool`; the Rust port allocates a
//!   per-call buffer in [`Set::for_each`] instead.
//! - `SizeBytes` uses `std::mem::size_of` instead of `unsafe.Sizeof`. The
//!   accounting structure mirrors Go's (struct size + 2 bytes per `b16his`
//!   entry + per-`bucket16` size + optional bitmap size), but the exact
//!   numbers differ from Go since struct layouts differ (e.g. Go's `Set`
//!   embeds a scratch bucket).
//! - `Subtract`'s "s is smaller" branch in Go deletes from `s` while
//!   iterating it via `ForEach`; the Rust port first collects the items to
//!   delete, then deletes them. The result is identical.

const BITS_PER_BUCKET: usize = 1 << 16;
const WORDS_PER_BUCKET: usize = BITS_PER_BUCKET / 64;
const SMALL_POOL_SIZE: usize = 56;

/// Port of Go `uint64set.Set` - a fast set for `u64`.
///
/// It should work faster than `HashSet<u64>` for semi-sparse `u64` values
/// such as MetricIDs generated by the storage layer.
#[derive(Default)]
pub struct Set {
    items_count: usize,
    buckets: Vec<Bucket32>,
}

impl Clone for Set {
    /// Port of Go `uint64set.Set.Clone` - returns an independent copy.
    fn clone(&self) -> Self {
        if self.items_count == 0 {
            // Return an empty set, so data could be added into it later.
            return Set::default();
        }
        Set {
            items_count: self.items_count,
            buckets: self.buckets.clone(),
        }
    }
}

impl Set {
    /// Port of Go `uint64set.Unmarshal` - creates a set from bytes.
    ///
    /// The first 8 src bytes contain the set length (number of the elements
    /// in the set), big-endian. The function reads exactly `8*length`
    /// subsequent bytes and constructs the set. The remaining src bytes are
    /// returned along with the set.
    pub fn unmarshal(src: &[u8]) -> Result<(Set, &[u8]), String> {
        if src.len() < 8 {
            return Err(format!(
                "cannot unmarshal uint64set; got {} bytes; want at least 8 bytes",
                src.len()
            ));
        }
        let s_len = read_u64_be(src);
        let mut src = &src[8..];
        if (src.len() as u64) / 8 < s_len {
            return Err(format!(
                "cannot unmarshal uint64set; got {} bytes; want at least {} bytes",
                src.len(),
                8 * s_len
            ));
        }
        let mut s = Set::default();
        for _ in 0..s_len {
            let e = read_u64_be(src);
            src = &src[8..];
            s.add(e);
        }
        Ok((s, src))
    }

    /// Port of Go `uint64set.Set.Marshal` - encodes the set as bytes.
    ///
    /// The first 8 bytes contain the length of the set, big-endian. The
    /// subsequent bytes are the `u64` elements. The result is appended to
    /// `dst`, i.e. the initial `dst` content is not overwritten.
    pub fn marshal(&self, mut dst: Vec<u8>) -> Vec<u8> {
        dst.extend_from_slice(&(self.len() as u64).to_be_bytes());
        self.for_each(|part| {
            for &e in part {
                dst.extend_from_slice(&e.to_be_bytes());
            }
            true
        });
        dst
    }

    fn fix_items_count(&mut self) {
        let mut n = 0;
        for b32 in &self.buckets {
            n += b32.get_len();
        }
        self.items_count = n;
    }

    /// Port of Go `uint64set.Set.SizeBytes` - an estimate of the set size in RAM.
    ///
    /// Uses `std::mem::size_of` in place of Go's `unsafe.Sizeof`; the
    /// accounting structure mirrors Go's, the exact numbers do not.
    pub fn size_bytes(&self) -> u64 {
        let mut n = std::mem::size_of::<Set>() as u64;
        for b32 in &self.buckets {
            n += b32.size_bytes();
        }
        n
    }

    /// Port of Go `uint64set.Set.Len` - the number of distinct values in the set.
    pub fn len(&self) -> usize {
        self.items_count
    }

    /// Returns true if the set contains no items. (No direct Go counterpart;
    /// required by Rust API conventions alongside `len`.)
    pub fn is_empty(&self) -> bool {
        self.items_count == 0
    }

    /// Port of Go `uint64set.Set.Add` - adds `x` to the set.
    pub fn add(&mut self, x: u64) {
        let hi32 = (x >> 32) as u32;
        let lo32 = x as u32;
        if let Some(first) = self.buckets.first_mut() {
            if first.hi == hi32 {
                // Manually inlined bucket32.add fast path, as in Go.
                let hi16 = (lo32 >> 16) as u16;
                let lo16 = lo32 as u16;
                let n = first.hint as usize;
                let added = if n < first.b16his.len() && first.b16his[n] == hi16 {
                    n < first.buckets.len() && first.buckets[n].add(lo16)
                } else {
                    first.add_slow(hi16, lo16)
                };
                if added {
                    self.items_count += 1;
                }
                return;
            }
        }
        for b32 in &mut self.buckets {
            if b32.hi == hi32 {
                if b32.add(lo32) {
                    self.items_count += 1;
                }
                return;
            }
        }
        let b32 = self.add_bucket32();
        b32.hi = hi32;
        b32.add(lo32);
        self.items_count += 1;
    }

    /// Port of Go `uint64set.Set.AddMulti` - adds all the items from `a`.
    ///
    /// It is usually faster than calling [`Set::add`] for each item in `a`.
    /// The caller is responsible for splitting `a` into items with clustered
    /// values.
    pub fn add_multi(&mut self, a: &[u64]) {
        if a.is_empty() {
            return;
        }
        let mut hi_prev = (a[0] >> 32) as u32;
        let mut i = 0;
        for (j, &x) in a.iter().enumerate() {
            let hi = (x >> 32) as u32;
            if hi == hi_prev {
                continue;
            }
            let count = self.get_or_create_bucket32(hi_prev).add_multi(&a[i..j]);
            self.items_count += count;
            hi_prev = hi;
            i = j;
        }
        let count = self.get_or_create_bucket32(hi_prev).add_multi(&a[i..]);
        self.items_count += count;
    }

    fn get_or_create_bucket32(&mut self, hi: u32) -> &mut Bucket32 {
        if let Some(pos) = self.buckets.iter().position(|b| b.hi == hi) {
            return &mut self.buckets[pos];
        }
        let b32 = self.add_bucket32();
        b32.hi = hi;
        b32
    }

    fn add_bucket32(&mut self) -> &mut Bucket32 {
        self.buckets.push(Bucket32::default());
        let idx = self.buckets.len() - 1;
        &mut self.buckets[idx]
    }

    /// Port of Go `uint64set.Set.Has` - verifies whether `x` exists in the set.
    pub fn has(&self, x: u64) -> bool {
        let hi32 = (x >> 32) as u32;
        let lo32 = x as u32;
        for b32 in &self.buckets {
            if b32.hi == hi32 {
                return b32.has(lo32);
            }
        }
        false
    }

    /// Port of Go `uint64set.Set.Del` - deletes `x` from the set.
    pub fn del(&mut self, x: u64) {
        let hi = (x >> 32) as u32;
        let lo = x as u32;
        if let Some(first) = self.buckets.first_mut() {
            if first.hi == hi {
                if first.del(lo) {
                    self.items_count -= 1;
                }
                return;
            }
        }
        for b32 in &mut self.buckets {
            if b32.hi == hi {
                if b32.del(lo) {
                    self.items_count -= 1;
                }
                return;
            }
        }
    }

    /// Port of Go `uint64set.Set.AppendTo` - appends all the items to `dst`
    /// and returns the result.
    ///
    /// The returned items are sorted. As in Go, `append_to` can mutate the
    /// set (it sorts the internal buckets), hence `&mut self`.
    pub fn append_to(&mut self, mut dst: Vec<u64>) -> Vec<u64> {
        // Pre-allocate memory for dst.
        dst.reserve(self.len());
        self.sort();
        for b32 in &self.buckets {
            b32.append_to(&mut dst);
        }
        dst
    }

    fn sort(&mut self) {
        // Sort the buckets if they aren't sorted yet.
        if !self.buckets.is_sorted_by_key(|b| b.hi) {
            self.buckets.sort_by_key(|b| b.hi);
        }
    }

    /// Port of Go `uint64set.Set.Union` - adds all the items from `a` to the set.
    pub fn union(&mut self, a: &Set) {
        self.union_internal(a);
    }

    /// Port of Go `uint64set.Set.UnionMayOwn` - adds all the items from `a`.
    ///
    /// In Go this may take ownership of `a`'s buckets as an optimization;
    /// Rust ownership makes that moot, so this delegates to [`Set::union`]
    /// (and, unlike in Go, `a` remains fully usable afterwards).
    pub fn union_may_own(&mut self, a: &Set) {
        self.union_internal(a);
    }

    fn union_internal(&mut self, a: &Set) {
        if a.is_empty() {
            // Fast path - nothing to union.
            return;
        }
        if self.is_empty() {
            // Fast path - copy `a` to `self`.
            *self = a.clone();
            return;
        }
        // Iterate `a`'s buckets in sorted order via an index permutation.
        // (Go makes a shallow clone of `a` and sorts it; `&Set` forbids that.)
        let order = sorted_bucket_order(a);
        self.sort();
        let mut i = 0;
        let mut j = 0;
        let s_buckets_len = self.buckets.len();
        loop {
            while i < s_buckets_len
                && j < order.len()
                && self.buckets[i].hi < a.buckets[order[j]].hi
            {
                i += 1;
            }
            if i >= s_buckets_len {
                while j < order.len() {
                    self.buckets.push(a.buckets[order[j]].clone());
                    j += 1;
                }
                break;
            }
            while j < order.len() && a.buckets[order[j]].hi < self.buckets[i].hi {
                self.buckets.push(a.buckets[order[j]].clone());
                j += 1;
            }
            if j >= order.len() {
                break;
            }
            if self.buckets[i].hi == a.buckets[order[j]].hi {
                self.buckets[i].union(&a.buckets[order[j]]);
                i += 1;
                j += 1;
            }
        }
        self.fix_items_count();
    }

    /// Port of Go `uint64set.Set.Intersect` - removes all the items missing
    /// in `a` from the set.
    pub fn intersect(&mut self, a: &Set) {
        if self.is_empty() || a.is_empty() {
            // Fast path - the result is empty.
            *self = Set::default();
            return;
        }
        // Iterate `a`'s buckets in sorted order via an index permutation.
        let order = sorted_bucket_order(a);
        self.sort();
        let mut i = 0;
        let mut j = 0;
        loop {
            while i < self.buckets.len()
                && j < order.len()
                && self.buckets[i].hi < a.buckets[order[j]].hi
            {
                self.buckets[i] = Bucket32::default();
                i += 1;
            }
            if i >= self.buckets.len() {
                break;
            }
            while j < order.len() && a.buckets[order[j]].hi < self.buckets[i].hi {
                j += 1;
            }
            if j >= order.len() {
                while i < self.buckets.len() {
                    self.buckets[i] = Bucket32::default();
                    i += 1;
                }
                break;
            }
            if self.buckets[i].hi == a.buckets[order[j]].hi {
                self.buckets[i].intersect(&a.buckets[order[j]]);
                i += 1;
                j += 1;
            }
        }
        self.fix_items_count();
    }

    /// Port of Go `uint64set.Set.Subtract` - removes from the set all the
    /// items shared between it and `a`.
    pub fn subtract(&mut self, a: &Set) {
        if self.is_empty() || a.is_empty() {
            // Fast path - nothing to subtract.
            return;
        }
        if self.len() >= a.len() {
            a.for_each(|part| {
                for &x in part {
                    self.del(x);
                }
                true
            });
        } else {
            // Go deletes from `s` while iterating it via ForEach; Rust
            // ownership forbids that, so collect the doomed items first.
            let mut to_del = Vec::new();
            self.for_each(|part| {
                for &x in part {
                    if a.has(x) {
                        to_del.push(x);
                    }
                }
                true
            });
            for x in to_del {
                self.del(x);
            }
        }
    }

    /// Port of Go `uint64set.Set.Equal` - returns true if the set contains
    /// the same items as `a`.
    pub fn equal(&self, a: &Set) -> bool {
        if self.len() != a.len() {
            return false;
        }
        let mut equal = true;
        a.for_each(|part| {
            for &x in part {
                if !self.has(x) {
                    equal = false;
                    return false;
                }
            }
            true
        });
        equal
    }

    /// Port of Go `uint64set.Set.ForEach` - calls `f` for all the items
    /// stored in the set.
    ///
    /// Each call to `f` receives an arbitrary part of the items stored in
    /// the set. The iteration is stopped if `f` returns false.
    pub fn for_each<F: FnMut(&[u64]) -> bool>(&self, mut f: F) {
        // Go pools this buffer in a sync.Pool; here it is a per-call buffer.
        let mut buf: Vec<u64> = Vec::new();
        for b32 in &self.buckets {
            if !b32.for_each(&mut f, &mut buf) {
                return;
            }
        }
    }
}

/// Returns the indexes of `a.buckets` in ascending `hi` order.
fn sorted_bucket_order(a: &Set) -> Vec<usize> {
    let mut order: Vec<usize> = (0..a.buckets.len()).collect();
    order.sort_by_key(|&k| a.buckets[k].hi);
    order
}

fn read_u64_be(src: &[u8]) -> u64 {
    let mut b = [0u8; 8];
    b.copy_from_slice(&src[..8]);
    u64::from_be_bytes(b)
}

/// Port of Go `uint64set.bucket32`.
#[derive(Default)]
struct Bucket32 {
    hi: u32,

    // hint may contain the bucket index of the last successful operation.
    // This allows saving CPU time on subsequent calls to the same bucket.
    // Go stores it atomically for lock-free concurrent reads; `&mut self`
    // discipline makes a plain field sufficient here.
    hint: u32,

    // b16his contains the high 16 bits for each bucket in `buckets`.
    //
    // It is always sorted.
    b16his: Vec<u16>,

    // buckets are sorted by b16his.
    buckets: Vec<Bucket16>,
}

impl Clone for Bucket32 {
    // Mirrors Go bucket32.copyTo: the hint is not copied.
    fn clone(&self) -> Self {
        Bucket32 {
            hi: self.hi,
            hint: 0,
            b16his: self.b16his.clone(),
            buckets: self.buckets.clone(),
        }
    }
}

impl Bucket32 {
    fn get_len(&self) -> usize {
        let mut n = 0;
        for b16 in &self.buckets {
            n += b16.get_len();
        }
        n
    }

    fn union(&mut self, a: &Bucket32) {
        let mut i = 0;
        let mut j = 0;
        let b_buckets_len = self.buckets.len();
        loop {
            while i < b_buckets_len && j < a.b16his.len() && self.b16his[i] < a.b16his[j] {
                i += 1;
            }
            if i >= b_buckets_len {
                while j < a.b16his.len() {
                    self.b16his.push(a.b16his[j]);
                    self.buckets.push(a.buckets[j].clone());
                    j += 1;
                }
                break;
            }
            while j < a.b16his.len() && a.b16his[j] < self.b16his[i] {
                self.b16his.push(a.b16his[j]);
                self.buckets.push(a.buckets[j].clone());
                j += 1;
            }
            if j >= a.b16his.len() {
                break;
            }
            if self.b16his[i] == a.b16his[j] {
                self.buckets[i].union(&a.buckets[j]);
                i += 1;
                j += 1;
            }
        }
        // Restore the bucket order, which could be violated during the merge above.
        if !self.b16his.is_sorted() {
            let mut pairs: Vec<(u16, Bucket16)> =
                self.b16his.drain(..).zip(self.buckets.drain(..)).collect();
            pairs.sort_by_key(|p| p.0);
            for (hi, b16) in pairs {
                self.b16his.push(hi);
                self.buckets.push(b16);
            }
        }
    }

    fn intersect(&mut self, a: &Bucket32) {
        let mut i = 0;
        let mut j = 0;
        loop {
            while i < self.b16his.len() && j < a.b16his.len() && self.b16his[i] < a.b16his[j] {
                self.buckets[i] = Bucket16::default();
                i += 1;
            }
            if i >= self.b16his.len() {
                break;
            }
            while j < a.b16his.len() && a.b16his[j] < self.b16his[i] {
                j += 1;
            }
            if j >= a.b16his.len() {
                while i < self.b16his.len() {
                    self.buckets[i] = Bucket16::default();
                    i += 1;
                }
                break;
            }
            if self.b16his[i] == a.b16his[j] {
                self.buckets[i].intersect(&a.buckets[j]);
                i += 1;
                j += 1;
            }
        }
        // Remove zero buckets.
        let his = std::mem::take(&mut self.b16his);
        let bs = std::mem::take(&mut self.buckets);
        for (hi, b16) in his.into_iter().zip(bs) {
            if b16.is_zero() {
                continue;
            }
            self.b16his.push(hi);
            self.buckets.push(b16);
        }
        self.hint = 0;
    }

    fn for_each<F: FnMut(&[u64]) -> bool>(&self, f: &mut F, buf: &mut Vec<u64>) -> bool {
        for (i, b16) in self.buckets.iter().enumerate() {
            let hi16 = self.b16his[i];
            buf.clear();
            b16.append_to(buf, self.hi, hi16);
            if !f(buf) {
                return false;
            }
        }
        true
    }

    fn size_bytes(&self) -> u64 {
        let mut n = std::mem::size_of::<Bucket32>() as u64;
        n += 2 * self.b16his.len() as u64;
        for b16 in &self.buckets {
            n += b16.size_bytes();
        }
        n
    }

    fn add(&mut self, x: u32) -> bool {
        let hi = (x >> 16) as u16;
        let lo = x as u16;
        let n = self.hint as usize;
        if n < self.b16his.len() && self.b16his[n] == hi {
            // Fast path - add to the previously used bucket.
            return n < self.buckets.len() && self.buckets[n].add(lo);
        }
        self.add_slow(hi, lo)
    }

    fn add_multi(&mut self, a: &[u64]) -> usize {
        if a.is_empty() {
            return 0;
        }
        let mut count = 0;
        let mut hi_prev = (a[0] >> 16) as u16;
        let mut i = 0;
        for (j, &x) in a.iter().enumerate() {
            let hi = (x >> 16) as u16;
            if hi == hi_prev {
                continue;
            }
            count += self.get_or_create_bucket16(hi_prev).add_multi(&a[i..j]);
            hi_prev = hi;
            i = j;
        }
        count += self.get_or_create_bucket16(hi_prev).add_multi(&a[i..]);
        count
    }

    fn get_or_create_bucket16(&mut self, hi: u16) -> &mut Bucket16 {
        let n = binary_search16(&self.b16his, hi);
        if n >= self.b16his.len() || self.b16his[n] != hi {
            return self.add_bucket_at_pos(hi, n);
        }
        &mut self.buckets[n]
    }

    fn add_slow(&mut self, hi: u16, lo: u16) -> bool {
        let n = binary_search16(&self.b16his, hi);
        if n >= self.b16his.len() || self.b16his[n] != hi {
            let b16 = self.add_bucket_at_pos(hi, n);
            b16.add(lo);
            return true;
        }
        self.hint = n as u32;
        n < self.buckets.len() && self.buckets[n].add(lo)
    }

    fn add_bucket_at_pos(&mut self, hi: u16, pos: usize) -> &mut Bucket16 {
        if pos >= self.b16his.len() {
            self.b16his.push(hi);
            self.buckets.push(Bucket16::default());
            let idx = self.buckets.len() - 1;
            return &mut self.buckets[idx];
        }
        self.b16his.insert(pos, hi);
        self.buckets.insert(pos, Bucket16::default());
        &mut self.buckets[pos]
    }

    fn has(&self, x: u32) -> bool {
        let hi = (x >> 16) as u16;
        let lo = x as u16;
        let n = binary_search16(&self.b16his, hi);
        if n >= self.b16his.len() || self.b16his[n] != hi {
            return false;
        }
        // Do not update the hint here, mirroring Go (which avoids it to keep
        // concurrent readers fast).
        n < self.buckets.len() && self.buckets[n].has(lo)
    }

    fn del(&mut self, x: u32) -> bool {
        let hi = (x >> 16) as u16;
        let lo = x as u16;
        let n = self.hint as usize;
        if n < self.b16his.len() && self.b16his[n] == hi {
            // Fast path - use the bucket from the previous operation.
            return n < self.buckets.len() && self.buckets[n].del(lo);
        }
        self.del_slow(hi, lo)
    }

    fn del_slow(&mut self, hi: u16, lo: u16) -> bool {
        let n = binary_search16(&self.b16his, hi);
        if n >= self.b16his.len() || self.b16his[n] != hi {
            return false;
        }
        self.hint = n as u32;
        n < self.buckets.len() && self.buckets[n].del(lo)
    }

    fn append_to(&self, dst: &mut Vec<u64>) {
        for (i, b16) in self.buckets.iter().enumerate() {
            let hi16 = self.b16his[i];
            b16.append_to(dst, self.hi, hi16);
        }
    }
}

/// Port of Go `uint64set.bucket16`.
#[derive(Clone)]
struct Bucket16 {
    bits: Option<Box<[u64; WORDS_PER_BUCKET]>>,
    small_pool: [u16; SMALL_POOL_SIZE],
    small_pool_len: usize,
}

impl Default for Bucket16 {
    fn default() -> Self {
        Bucket16 {
            bits: None,
            small_pool: [0; SMALL_POOL_SIZE],
            small_pool_len: 0,
        }
    }
}

impl Bucket16 {
    fn is_zero(&self) -> bool {
        self.bits.is_none() && self.small_pool_len == 0
    }

    fn get_len(&self) -> usize {
        match &self.bits {
            None => self.small_pool_len,
            Some(bits) => {
                let mut n = 0;
                for &x in bits.iter() {
                    if x > 0 {
                        n += x.count_ones() as usize;
                    }
                }
                n
            }
        }
    }

    fn union(&mut self, a: &Bucket16) {
        if let Some(ab) = &a.bits {
            if let Some(bb) = &mut self.bits {
                // Fast path - use bitwise ops.
                for (bx, &ax) in bb.iter_mut().zip(ab.iter()) {
                    *bx |= ax;
                }
                return;
            }
        }

        // Slow path.
        let mut buf = Vec::new();
        a.append_to(&mut buf, 0, 0);
        for &x in &buf {
            self.add(x as u16);
        }
    }

    fn intersect(&mut self, a: &Bucket16) {
        if let Some(ab) = &a.bits {
            if let Some(bb) = &mut self.bits {
                // Fast path - use bitwise ops.
                for (bx, &ax) in bb.iter_mut().zip(ab.iter()) {
                    *bx &= ax;
                }
                return;
            }
        }

        // Slow path.
        let mut buf = Vec::new();
        self.append_to(&mut buf, 0, 0);
        for &x in &buf {
            let x16 = x as u16;
            if !a.has(x16) {
                self.del(x16);
            }
        }
    }

    fn size_bytes(&self) -> u64 {
        let mut n = std::mem::size_of::<Bucket16>();
        if self.bits.is_some() {
            n += std::mem::size_of::<[u64; WORDS_PER_BUCKET]>();
        }
        n as u64
    }

    fn add(&mut self, x: u16) -> bool {
        match &mut self.bits {
            None => self.add_to_small_pool(x),
            Some(bits) => {
                let (word_num, bit_mask) = get_word_num_bit_mask(x);
                let ok = bits[word_num] & bit_mask == 0;
                if ok {
                    bits[word_num] |= bit_mask;
                }
                ok
            }
        }
    }

    fn add_multi(&mut self, a: &[u64]) -> usize {
        if self.bits.is_none() {
            if self.small_pool_len + a.len() <= SMALL_POOL_SIZE {
                // Slow path.
                let mut count = 0;
                for &x in a {
                    if self.add_to_small_pool(x as u16) {
                        count += 1;
                    }
                }
                return count;
            }
            self.switch_small_pool_to_bits();
        }

        // Fast path.
        let Some(bits) = self.bits.as_deref_mut() else {
            return 0; // unreachable: bits is always Some here
        };
        let mut count = 0;
        for &x in a {
            let (word_num, bit_mask) = get_word_num_bit_mask(x as u16);
            if bits[word_num] & bit_mask == 0 {
                bits[word_num] |= bit_mask;
                count += 1;
            }
        }
        count
    }

    fn add_to_small_pool(&mut self, x: u16) -> bool {
        if self.has_in_small_pool(x) {
            return false;
        }
        if self.small_pool_len < SMALL_POOL_SIZE {
            self.small_pool[self.small_pool_len] = x;
            self.small_pool_len += 1;
            return true;
        }
        self.switch_small_pool_to_bits();
        self.add(x);
        true
    }

    fn switch_small_pool_to_bits(&mut self) {
        let small_pool_len = self.small_pool_len;
        self.small_pool_len = 0;
        self.bits = Some(Box::new([0u64; WORDS_PER_BUCKET]));
        let pool = self.small_pool;
        for &v in &pool[..small_pool_len] {
            self.add(v);
        }
    }

    fn has(&self, x: u16) -> bool {
        match &self.bits {
            None => self.has_in_small_pool(x),
            Some(bits) => {
                let (word_num, bit_mask) = get_word_num_bit_mask(x);
                bits[word_num] & bit_mask != 0
            }
        }
    }

    fn has_in_small_pool(&self, x: u16) -> bool {
        self.small_pool[..self.small_pool_len].contains(&x)
    }

    fn del(&mut self, x: u16) -> bool {
        match &mut self.bits {
            None => self.del_from_small_pool(x),
            Some(bits) => {
                let (word_num, bit_mask) = get_word_num_bit_mask(x);
                let word = &mut bits[word_num];
                let ok = *word & bit_mask != 0;
                *word &= !bit_mask;
                ok
            }
        }
    }

    fn del_from_small_pool(&mut self, x: u16) -> bool {
        if let Some(i) = self.small_pool[..self.small_pool_len]
            .iter()
            .position(|&v| v == x)
        {
            self.small_pool.copy_within(i + 1..self.small_pool_len, i);
            self.small_pool_len -= 1;
            return true;
        }
        false
    }

    fn append_to(&self, dst: &mut Vec<u64>, hi: u32, hi16: u16) {
        let hi64 = (hi as u64) << 32 | (hi16 as u64) << 16;
        match &self.bits {
            None => {
                // Sort a copy of the small pool, since `self` must stay
                // readonly (mirrors Go, which sorts a copy to avoid data
                // races between concurrent readers).
                let mut pool = self.small_pool;
                let a = &mut pool[..self.small_pool_len];
                if a.len() > 1 && !a.is_sorted() {
                    a.sort_unstable();
                }
                for &v in a.iter() {
                    dst.push(hi64 | v as u64);
                }
            }
            Some(bits) => {
                let mut word_num: u64 = 0;
                for &w in bits.iter() {
                    if w == 0 {
                        word_num += 1;
                        continue;
                    }
                    let mut word = w;
                    let x64 = hi64 | (word_num * 64);
                    loop {
                        let tzn = word.trailing_zeros() as u64;
                        if tzn >= 64 {
                            break;
                        }
                        word &= !(1u64 << tzn);
                        dst.push(x64 | tzn);
                    }
                    word_num += 1;
                }
            }
        }
    }
}

fn get_word_num_bit_mask(x: u16) -> (usize, u64) {
    let word_num = (x / 64) as usize;
    let bit_mask = 1u64 << (x & 63);
    (word_num, bit_mask)
}

// Port of Go `uint64set.binarySearch16`, including the fast path for values
// scanned in ascending order.
fn binary_search16(u16s: &[u16], x: u16) -> usize {
    let n = u16s.len();
    if n > 0 && u16s[n - 1] < x {
        // Fast path for values scanned in ascending order.
        return n;
    }
    let mut i = 0;
    let mut j = n;
    while i < j {
        let h = (i + j) >> 1;
        if u16s[h] < x {
            i = h + 1;
        } else {
            j = h;
        }
    }
    i
}

