    fn test_set_ops() {
        let f = |a: &[u64], b: &[u64]| check_set_ops(a, b);

        f(&[], &[]);
        f(&[1], &[]);
        f(&[1, 2, 3], &[]);
        f(&[1, 2, 3, 1 << 16, 1 << 32, 2 << 32], &[]);
        f(&[1], &[1]);
        f(&[0], &[1 << 16]);
        f(&[1], &[1 << 16]);
        f(&[1], &[4 << 16]);
        f(&[1], &[1 << 32]);
        f(&[1], &[1 << 32, 2 << 32]);
        f(&[1], &[2 << 32]);
        f(&[1, (1 << 16) - 1], &[1 << 16]);
        f(&[0, (1 << 16) - 1], &[1 << 16, (1 << 16) - 1]);
        f(
            &[0, (1 << 16) - 1],
            &[1 << 16, (1 << 16) - 1, 2 << 16, 8 << 16],
        );
        f(&[0], &[1 << 16, (1 << 16) - 1, 2 << 16, 8 << 16]);
        f(&[0, 2 << 16], &[1 << 16]);
        f(&[0, 2 << 16], &[1 << 16, 3 << 16]);
        f(&[0, 2 << 16], &[1 << 16, 2 << 16]);
        f(&[0, 2 << 16], &[1 << 16, 2 << 16, 3 << 16]);
        f(&[0, 2 << 32], &[1 << 32]);
        f(&[0, 2 << 32], &[1 << 32, 3 << 32]);
        f(&[0, 2 << 32], &[1 << 32, 2 << 32]);
        f(&[0, 2 << 32], &[1 << 32, 2 << 32, 3 << 32]);

        let mut a: Vec<u64> = Vec::new();
        for i in 0..100u64 {
            a.push(i);
        }
        let mut b: Vec<u64> = Vec::new();
        for i in (1u64 << 16)..(1 << 16) + 1000 {
            b.push(i);
        }
        f(&a, &b);

        for i in (1u64 << 16) - 100..(1 << 16) + 100 {
            a.push(i);
        }
        for i in (1u64 << 32)..(1 << 32) + (1 << 16) + 200 {
            b.push(i);
        }
        f(&a, &b);

        let mut rng = StdRng::seed_from_u64(1);
        for _ in 0..10 {
            a.clear();
            b.clear();
            for _ in 0..1000 {
                a.push(rng.random_range(0..1_000_000u64));
                b.push(rng.random_range(0..1_000_000u64));
            }
            f(&a, &b);
        }
    }

    fn check_set_ops(a: &[u64], b: &[u64]) {
        let mut m_union: HashSet<u64> = HashSet::new();
        let mut m_intersect: HashSet<u64> = HashSet::new();
        let mut ma: HashSet<u64> = HashSet::new();
        let mut sa = Set::default();
        let mut sb = Set::default();
        for &v in a {
            sa.add(v);
            ma.insert(v);
            m_union.insert(v);
        }
        for &v in b {
            sb.add(v);
            m_union.insert(v);
            if ma.contains(&v) {
                m_intersect.insert(v);
            }
        }
        let sa_orig = sa.clone();
        assert!(sa_orig.equal(&sa), "saOrig must be equal to sa");
        let sb_orig = sb.clone();
        assert!(sb_orig.equal(&sb), "sbOrig must be equal to sb");

        // Verify sa.union(sb)
        sa.union(&sb);
        if let Err(err) = expect_equal(&mut sa, &m_union) {
            panic!("invalid sa.union(sb): {err}");
        }
        assert!(
            sb_orig.equal(&sb),
            "sbOrig must be equal to sb after sa.union(sb)"
        );

        // Verify sb.union(sa)
        let sa = sa_orig.clone();
        sb.union(&sa);
        if let Err(err) = expect_equal(&mut sb, &m_union) {
            panic!("invalid sb.union(sa): {err}");
        }
        assert!(
            sa_orig.equal(&sa),
            "saOrig must be equal to sa after sb.union(sa)"
        );

        // Verify sa.union_may_own(sb)
        let mut sa = sa_orig.clone();
        let mut sb = sb_orig.clone();
        sa.union_may_own(&sb);
        if let Err(err) = expect_equal(&mut sa, &m_union) {
            panic!("invalid sa.union_may_own(sb): {err}");
        }
        assert!(
            sb_orig.equal(&sb),
            "sbOrig must be equal to sb after sa.union_may_own(sb)"
        );

        // Verify sb.union_may_own(sa)
        let sa = sa_orig.clone();
        sb.union_may_own(&sa);
        if let Err(err) = expect_equal(&mut sb, &m_union) {
            panic!("invalid sb.union_may_own(sa): {err}");
        }
        assert!(
            sa_orig.equal(&sa),
            "saOrig must be equal to sa after sb.union_may_own(sa)"
        );

        // Verify sa.intersect(sb)
        let mut sa = sa_orig.clone();
        let mut sb = sb_orig.clone();
        sa.intersect(&sb);
        if let Err(err) = expect_equal(&mut sa, &m_intersect) {
            panic!("invalid sa.intersect(sb): {err}");
        }
        assert!(
            sb_orig.equal(&sb),
            "sbOrig must be equal to sb after sa.intersect(sb)"
        );

        // Verify sb.intersect(sa)
        let sa = sa_orig.clone();
        sb.intersect(&sa);
        if let Err(err) = expect_equal(&mut sb, &m_intersect) {
            panic!("invalid sb.intersect(sa): {err}");
        }
        assert!(
            sa_orig.equal(&sa),
            "saOrig must be equal to sa after sb.intersect(sa)"
        );

        // Verify sa.subtract(sb)
        let mut m_subtract_ab: HashSet<u64> = HashSet::new();
        for &v in a {
            m_subtract_ab.insert(v);
        }
        for &v in b {
            m_subtract_ab.remove(&v);
        }
        let mut sa = sa_orig.clone();
        let mut sb = sb_orig.clone();
        sa.subtract(&sb);
        if let Err(err) = expect_equal(&mut sa, &m_subtract_ab) {
            panic!("invalid sa.subtract(sb): {err}");
        }
        assert!(
            sb_orig.equal(&sb),
            "sbOrig must be equal to sb after sa.subtract(sb)"
        );

        // Verify sb.subtract(sa)
        let mut m_subtract_ba: HashSet<u64> = HashSet::new();
        for &v in b {
            m_subtract_ba.insert(v);
        }
        for &v in a {
            m_subtract_ba.remove(&v);
        }
        let sa = sa_orig.clone();
        sb.subtract(&sa);
        if let Err(err) = expect_equal(&mut sb, &m_subtract_ba) {
            panic!("invalid sb.subtract(sa): {err}");
        }
        assert!(
            sa_orig.equal(&sa),
            "saOrig must be equal to sa after sb.subtract(sa)"
        );
    }

    // Port of Go expectEqual.
    fn expect_equal(s: &mut Set, m: &HashSet<u64>) -> Result<(), String> {
        if s.len() != m.len() {
            return Err(format!(
                "unexpected s.len(); got {}; want {}\ns={:?}\nm={:?}",
                s.len(),
                m.len(),
                s.append_to(Vec::new()),
                m
            ));
        }
        for v in s.append_to(Vec::new()) {
            if !m.contains(&v) {
                return Err(format!(
                    "missing value {} in m; s={:?}\nm={:?}",
                    v,
                    s.append_to(Vec::new()),
                    m
                ));
            }
        }

        // Additional check via s.has()
        for &v in m {
            if !s.has(v) {
                return Err(format!(
                    "missing value {} in s; s={:?}\nm={:?}",
                    v,
                    s.append_to(Vec::new()),
                    m
                ));
            }
        }

        // Extra check via s.for_each()
        let mut err = None;
        s.for_each(|part| {
            for &v in part {
                if !m.contains(&v) {
                    err = Some(format!("missing value {v} in m inside s.for_each"));
                    return false;
                }
            }
            true
        });
        match err {
            Some(e) => Err(e),
            None => Ok(()),
        }
    }

