    fn now_nanos() -> u64 {
        SystemTime::now()
            .duration_since(UNIX_EPOCH)
            .expect("system time before Unix epoch")
            .as_nanos() as u64
    }

    fn test_set_basic_ops(items_count: usize) {
        let mut s = Set::default();

        let offset = now_nanos();

        // Verify operations on an empty set.
        // (Go verifies a nil *Set here; Rust has no nil, so the empty set is
        // used instead. Go's `sNil.SizeBytes() == 0` has no Rust equivalent
        // since an empty Set still occupies size_of::<Set>() bytes.)
        {
            let s_empty = Set::default();
            assert!(
                !s_empty.has(123),
                "empty set shouldn't contain any item; found 123"
            );
            assert_eq!(s_empty.len(), 0, "unexpected empty set len");
            let result = s_empty.clone().append_to(Vec::new());
            assert!(result.is_empty(), "empty set append_to must return empty");
            let buf = vec![1u64, 2, 3];
            let result = s_empty.clone().append_to(buf.clone());
            assert_eq!(result, buf, "empty set append_to(buf) must return buf");
            let mut s_copy = s_empty.clone();
            assert_eq!(s_copy.len(), 0, "unexpected s_copy.len() from empty set");
            s_copy.add(123);
            assert_eq!(
                s_copy.len(),
                1,
                "unexpected s_copy.len() after adding an item"
            );
            s_copy.add(123);
            assert_eq!(
                s_copy.len(),
                1,
                "unexpected s_copy.len() after adding an item twice"
            );
            assert!(s_copy.has(123), "s_copy must contain 123");
            s_copy.del(123);
            assert_eq!(
                s_copy.len(),
                0,
                "unexpected s_copy.len() after deleting the item"
            );
            s_copy.del(123);
            assert_eq!(
                s_copy.len(),
                0,
                "unexpected s_copy.len() after double deleting the item"
            );
        }

        // Verify forward Add
        let items_count = (items_count / 2) * 2;
        for i in 0..items_count / 2 {
            s.add(i as u64 + offset);
        }
        assert_eq!(
            s.len(),
            items_count / 2,
            "unexpected s.len() after forward add"
        );
        assert!(s.size_bytes() > 0, "s.size_bytes() must be greater than 0");

        // Verify backward Add
        for i in 0..items_count / 2 {
            s.add((items_count - i - 1) as u64 + offset);
        }
        assert_eq!(
            s.len(),
            items_count,
            "unexpected s.len() after backward add"
        );

        // Verify repeated Add
        for i in 0..items_count / 2 {
            s.add(i as u64 + offset);
        }
        assert_eq!(
            s.len(),
            items_count,
            "unexpected s.len() after repeated add"
        );

        // Verify Has on existing bits
        for i in 0..items_count {
            assert!(
                s.has(i as u64 + offset),
                "missing bit {}",
                i as u64 + offset
            );
        }

        // Verify Has on missing bits
        for i in items_count..2 * items_count {
            assert!(
                !s.has(i as u64 + offset),
                "unexpected bit found: {}",
                i as u64 + offset
            );
        }

        // Verify Clone and Equal
        let s_copy = s.clone();
        assert_eq!(s_copy.len(), items_count, "unexpected s_copy.len()");
        for i in 0..items_count {
            assert!(
                s_copy.has(i as u64 + offset),
                "missing bit {} on s_copy",
                i as u64 + offset
            );
        }
        assert!(s_copy.equal(&s), "s must equal to s_copy");
        assert!(s.equal(&s_copy), "s_copy must equal to s");
        if !s.is_empty() {
            let s_empty = Set::default();
            assert!(!s.equal(&s_empty), "s mustn't equal to s_empty");
            let mut s_new = s.clone();
            s_new.del(offset);
            assert!(!s_new.equal(&s), "s_new mustn't equal to s");
            assert!(!s.equal(&s_new), "s mustn't equal to s_new");
            s_new.add(offset - 123);
            assert!(!s_new.equal(&s), "s_new mustn't equal to s");
            assert!(!s.equal(&s_new), "s mustn't equal to s_new");
        }

        // Verify AppendTo
        let mut a = s.append_to(Vec::new());
        assert_eq!(
            a.len(),
            items_count,
            "unexpected len of exported array; array:\n{a:?}"
        );
        assert!(
            a.is_sorted(),
            "unsorted result returned from append_to: {a:?}"
        );
        let mut m: HashSet<u64> = HashSet::new();
        for &x in &a {
            m.insert(x);
        }
        for i in 0..items_count {
            assert!(
                m.contains(&(i as u64 + offset)),
                "missing bit {} in the exported bits",
                i as u64 + offset
            );
        }

        // Verify ForEach
        {
            let mut s = Set::default();
            let mut m: HashSet<u64> = HashSet::new();
            for i in 0..items_count {
                let v = i as u64 + offset;
                s.add(v);
                m.insert(v);
            }

            // Verify visiting all the items.
            s.for_each(|part| {
                for &v in part {
                    assert!(m.contains(&v), "unexpected value v={v} passed to for_each");
                    m.remove(&v);
                }
                true
            });
            assert!(m.is_empty(), "for_each didn't visit {} items", m.len());

            // Verify fast stop
            let mut calls = 0;
            s.for_each(|_| {
                calls += 1;
                false
            });
            if items_count > 0 {
                assert_eq!(
                    calls, 1,
                    "unexpected number of for_each callback calls; want 1"
                );
            }

            // Verify for_each on an empty set (Go: nil set).
            let s1 = Set::default();
            s1.for_each(|_| {
                panic!("callback shouldn't be called on empty set");
            });
        }

        // Verify union
        {
            const UNION_OFFSET: usize = 12345;
            let mut s1 = Set::default();
            let mut s2 = Set::default();
            for i in 0..items_count {
                s1.add(i as u64 + offset);
                s2.add(i as u64 + offset + UNION_OFFSET as u64);
            }
            s1.union(&s2);
            let mut expected_len = 2 * items_count;
            if items_count > UNION_OFFSET {
                expected_len = items_count + UNION_OFFSET;
            }
            assert_eq!(s1.len(), expected_len, "unexpected s1.len() after union");

            // Verify union on empty set.
            let mut s3 = Set::default();
            s3.union(&s1);
            let expected_len = s1.len();
            assert_eq!(
                s3.len(),
                expected_len,
                "unexpected s3.len() after union with empty set"
            );
            let s4 = Set::default();
            let expected_len = s3.len();
            s3.union(&s4);
            assert_eq!(
                s3.len(),
                expected_len,
                "unexpected s3.len() after union with empty set"
            );
        }

        // Verify union_may_own
        {
            const UNION_OFFSET: usize = 12345;
            let mut s1 = Set::default();
            let mut s2 = Set::default();
            for i in 0..items_count {
                s1.add(i as u64 + offset);
                s2.add(i as u64 + offset + UNION_OFFSET as u64);
            }
            s1.union_may_own(&s2);
            let mut expected_len = 2 * items_count;
            if items_count > UNION_OFFSET {
                expected_len = items_count + UNION_OFFSET;
            }
            assert_eq!(s1.len(), expected_len, "unexpected s1.len() after union");

            // Verify union on empty set.
            let mut s3 = Set::default();
            let expected_len = s1.len();
            s3.union_may_own(&s1);
            assert_eq!(
                s3.len(),
                expected_len,
                "unexpected s3.len() after union with empty set"
            );
            let s4 = Set::default();
            let expected_len = s3.len();
            s3.union_may_own(&s4);
            assert_eq!(
                s3.len(),
                expected_len,
                "unexpected s3.len() after union with empty set"
            );
        }

        // Verify intersect
        {
            // Verify s1.intersect(s2) and s2.intersect(s1)
            let mut s1 = Set::default();
            let mut s2 = Set::default();
            for &intersect_offset in &[123u64, 12345, (1 << 32) + 4343] {
                s1 = Set::default();
                s2 = Set::default();
                for i in 0..items_count {
                    s1.add(i as u64 + offset);
                    s2.add(i as u64 + offset + intersect_offset);
                }
                let mut expected_len = 0usize;
                if items_count as u64 > intersect_offset {
                    expected_len = (items_count as u64 - intersect_offset) as usize;
                }
                let mut s1_copy = s1.clone();
                s1_copy.intersect(&s2);
                assert_eq!(
                    s1_copy.len(),
                    expected_len,
                    "unexpected s1.len() after intersect"
                );
                s2.intersect(&s1);
                assert_eq!(
                    s2.len(),
                    expected_len,
                    "unexpected s2.len() after intersect"
                );
            }

            // Verify intersect on empty set.
            let s3 = Set::default();
            s2.intersect(&s3);
            let expected_len = 0;
            assert_eq!(
                s2.len(),
                expected_len,
                "unexpected s2.len() after intersect with empty set"
            );
            let mut s4 = Set::default();
            s4.intersect(&s1);
            assert_eq!(
                s4.len(),
                expected_len,
                "unexpected s4.len() after intersect with empty set"
            );
        }

        // Verify subtract
        {
            const SUBTRACT_OFFSET: usize = 12345;
            let mut s1 = Set::default();
            let mut s2 = Set::default();
            for i in 0..items_count {
                s1.add(i as u64 + offset);
                s2.add(i as u64 + offset + SUBTRACT_OFFSET as u64);
            }
            s1.subtract(&s2);
            let expected_len = items_count.min(SUBTRACT_OFFSET);
            assert_eq!(s1.len(), expected_len, "unexpected s1.len() after subtract");

            // Verify subtract from empty set.
            let mut s3 = Set::default();
            s3.subtract(&s2);
            assert_eq!(
                s3.len(),
                0,
                "unexpected s3.len() after subtract from empty set"
            );
        }

        // Verify Del
        let mut items_deleted = 0;
        for i in items_count / 2..items_count - items_count / 4 {
            s.del(i as u64 + offset);
            items_deleted += 1;
        }
        assert_eq!(
            s.len(),
            items_count - items_deleted,
            "unexpected s.len() after del"
        );
        a.clear();
        a = s.append_to(a);
        assert_eq!(
            a.len(),
            items_count - items_deleted,
            "unexpected len of exported array"
        );
        let mut m: HashSet<u64> = HashSet::new();
        for &x in &a {
            m.insert(x);
        }
        for i in 0..items_count {
            if i >= items_count / 2 && i < items_count - items_count / 4 {
                assert!(
                    !m.contains(&(i as u64 + offset)),
                    "unexpected bit found after deleting: {}",
                    i as u64 + offset
                );
            } else {
                assert!(
                    m.contains(&(i as u64 + offset)),
                    "missing bit {} in the exported bits after deleting",
                    i as u64 + offset
                );
            }
        }

        // Try Del for non-existing items
        for i in items_count / 2..items_count - items_count / 4 {
            s.del(i as u64 + offset);
            s.del(i as u64 + offset);
            s.del(i as u64 + offset + items_count as u64);
        }
        assert_eq!(
            s.len(),
            items_count - items_deleted,
            "unexpected s.len() after del for non-existing items"
        );

        // Verify s_copy has the original data
        assert_eq!(s_copy.len(), items_count, "unexpected s_copy.len()");
        for i in 0..items_count {
            assert!(
                s_copy.has(i as u64 + offset),
                "missing bit {} on s_copy",
                i as u64 + offset
            );
        }
    }

    // Port of Go TestSetSparseItems (one test per subtest items count).
    #[test]
    fn test_set_sparse_items_100() {
        test_set_sparse_items(100);
    }
    #[test]
    fn test_set_sparse_items_1000() {
        test_set_sparse_items(1000);
    }
    #[test]
    fn test_set_sparse_items_10000() {
        test_set_sparse_items(10_000);
    }

    fn test_set_sparse_items(items_count: usize) {
        let mut rng = StdRng::seed_from_u64(1);
        let mut s = Set::default();
        let mut m: HashSet<u64> = HashSet::new();
        for _ in 0..items_count {
            let x = rng.random::<u64>();
            s.add(x);
            m.insert(x);
        }
        assert_eq!(s.len(), m.len(), "unexpected len()");
        assert!(
            s.size_bytes() > 0,
            "size_bytes() must return value greater than 0"
        );

        // Check Has
        for &x in &m {
            assert!(s.has(x), "missing item {x}");
        }
        for i in 0..items_count {
            let x = i as u64;
            if m.contains(&x) {
                continue;
            }
            assert!(!s.has(x), "unexpected item found {x}");
        }

        // Check Clone
        let s_copy = s.clone();
        assert_eq!(s_copy.len(), m.len(), "unexpected s_copy.len()");
        for &x in &m {
            assert!(s_copy.has(x), "missing item {x} on s_copy");
        }

        // Check AppendTo
        let mut a = s.append_to(Vec::new());
        assert_eq!(a.len(), m.len(), "unexpected len for append_to result");
        assert!(
            a.is_sorted(),
            "unsorted result returned from append_to: {a:?}"
        );
        for &x in &a {
            assert!(
                m.contains(&x),
                "unexpected item found in append_to result: {x}"
            );
        }

        // Check Del
        for &x in &m {
            s.del(x);
            s.del(x);
            s.del(x.wrapping_add(1));
            s.del(x.wrapping_sub(1));
        }
        assert_eq!(s.len(), 0, "unexpected number of items left after del");
        a.clear();
        a = s.append_to(a);
        assert_eq!(
            a.len(),
            0,
            "unexpected number of items returned from append_to after del: {a:?}"
        );

        // Check items in s_copy
        assert_eq!(s_copy.len(), m.len(), "unexpected s_copy.len() after del");
        for &x in &m {
            assert!(s_copy.has(x), "missing item {x} on s_copy after del");
        }
    }

    // Port of Go TestAddMulti.
    #[test]
    fn test_add_multi() {
        let f = |a: &[u64]| {
            let mut s1 = Set::default();
            let mut s2 = Set::default();
            s1.add_multi(a);
            for &x in a {
                s2.add(x);
            }
            assert_eq!(
                s1.len(),
                s2.len(),
                "unexpected number of items in the set;\nset:\n{:?}",
                s1.append_to(Vec::new())
            );
            for &x in a {
                assert!(s1.has(x), "missing item {x} in the set");
            }
            let a1 = s1.append_to(Vec::new());
            let a2 = s2.append_to(Vec::new());
            assert_eq!(a1, a2, "unexpected items in the set");

            // Try removing and then adding again all the items via add_multi to s1.
            for &x in a {
                s1.del(x);
            }
            assert_eq!(
                s1.len(),
                0,
                "non-zero number of items left after deletion: {}",
                s1.len()
            );
            s1.add_multi(a);
            assert_eq!(
                s1.len(),
                s2.len(),
                "unexpected number of items in the reused set"
            );
            for &x in a {
                assert!(s1.has(x), "missing item {x} in the reused set");
            }
            let a1 = s1.append_to(Vec::new());
            let a2 = s2.append_to(Vec::new());
            assert_eq!(a1, a2, "unexpected items in the reused set");
        };
        f(&[]);
        f(&[1]);
        f(&[0, 1, 2, 3, 4, 5]);
        f(&[0, 1 << 16, 2 << 16, (2 << 16) + 1]);
        f(&[
            0,
            1 << 16,
            2 << 16,
            (2 << 16) + 1,
            1 << 32,
            2 << 32,
            (2 << 32) + 1,
        ]);

        let mut a: Vec<u64> = Vec::new();
        for i in 0..32000u64 {
            a.push(i);
        }
        f(&a);

        let mut a: Vec<u64> = Vec::new();
        for i in 0..32000u64 {
            a.push((1 << 16) + i);
        }
        f(&a);

        let mut a: Vec<u64> = Vec::new();
        for i in 0..100_000u64 {
            a.push((1 << 32) + i);
        }
        f(&a);
    }

    // Port of Go TestSubtract.
    #[test]
    fn test_subtract() {
        fn f(a: &mut Set, b: &mut Set, want: &mut Set) {
            let b_before = b.append_to(Vec::new());
            a.subtract(b);
            let b_after = b.append_to(Vec::new());
            let got_values = a.append_to(Vec::new());
            let want_values = want.append_to(Vec::new());
            assert_eq!(want_values, got_values, "unexpected a set");
            assert_eq!(b_before, b_after, "unexpected b set");
        }

        // Go's helper s(start, end, se...) with additional (start, end) pairs.
        fn s(ranges: &[(u64, u64)]) -> Set {
            let mut set = Set::default();
            for &(start, end) in ranges {
                for i in start..=end {
                    set.add(i);
                }
            }
            set
        }

        // - no overlap
        // - a values before b values
        // - len(a) > len(b)
        let mut a = s(&[(1, 500_000)]);
        let mut b = s(&[(500_001, 600_000)]);
        let mut want = s(&[(1, 500_000)]);
        f(&mut a, &mut b, &mut want);

        // - no overlap
        // - a values after b values
        // - len(a) > len(b)
        let mut a = s(&[(500_001, 1_000_000)]);
        let mut b = s(&[(400_000, 500_000)]);
        let mut want = s(&[(500_001, 1_000_000)]);
        f(&mut a, &mut b, &mut want);

        // - no overlap
        // - a values before b values
        // - len(a) < len(b)
        let mut a = s(&[(400_000, 500_000)]);
        let mut b = s(&[(500_001, 1_000_000)]);
        let mut want = s(&[(400_000, 500_000)]);
        f(&mut a, &mut b, &mut want);

        // - no overlap
        // - a values after b values
        // - len(a) < len(b)
        let mut a = s(&[(500_001, 600_000)]);
        let mut b = s(&[(1, 500_000)]);
        let mut want = s(&[(500_001, 600_000)]);
        f(&mut a, &mut b, &mut want);

        // - overlap on the left side
        // - len(a) > len(b)
        let mut a = s(&[(500_000, 1_000_000)]);
        let mut b = s(&[(400_000, 600_000)]);
        let mut want = s(&[(600_001, 1_000_000)]);
        f(&mut a, &mut b, &mut want);

        // - overlap on the right side
        // - len(a) > len(b)
        let mut a = s(&[(1, 500_000)]);
        let mut b = s(&[(400_001, 600_000)]);
        let mut want = s(&[(1, 400_000)]);
        f(&mut a, &mut b, &mut want);

        // - overlap on the left side
        // - len(a) < len(b)
        let mut a = s(&[(400_000, 600_000)]);
        let mut b = s(&[(500_001, 1_000_000)]);
        let mut want = s(&[(400_000, 500_000)]);
        f(&mut a, &mut b, &mut want);

        // - overlap on the right side
        // - len(a) < len(b)
        let mut a = s(&[(400_000, 600_000)]);
        let mut b = s(&[(1, 500_000)]);
        let mut want = s(&[(500_001, 600_000)]);
        f(&mut a, &mut b, &mut want);

        // same
        let mut a = s(&[(1, 500_000)]);
        let mut b = s(&[(1, 500_000)]);
        let mut want = Set::default();
        f(&mut a, &mut b, &mut want);

        // b is a subset of a
        let mut a = s(&[(1, 500_000)]);
        let mut b = s(&[(100_001, 400_000)]);
        let mut want = s(&[(1, 100_000), (400_001, 500_000)]);
        f(&mut a, &mut b, &mut want);

        // a is a subset of b
        let mut a = s(&[(100_001, 400_000)]);
        let mut b = s(&[(1, 500_000)]);
        let mut want = Set::default();
        f(&mut a, &mut b, &mut want);

        // a with intervals
        let mut a = s(&[(1, 200_000), (400_000, 500_000)]);
        let mut b = s(&[(150_001, 450_000)]);
        let mut want = s(&[(1, 150_000), (450_001, 500_000)]);
        f(&mut a, &mut b, &mut want);

        // b with intervals
        let mut a = s(&[(1, 500_000)]);
        let mut b = s(&[(200_001, 300_000), (400_001, 500_000)]);
        let mut want = s(&[(1, 200_000), (300_001, 400_000)]);
        f(&mut a, &mut b, &mut want);

        // subtract more than once.
        let mut a = s(&[(1, 500_000)]);
        let mut b1 = s(&[(100_001, 200_000)]);
        let mut want1 = s(&[(1, 100_000), (200_001, 500_000)]);
        let mut b2 = s(&[(300_001, 400_000)]);
        let mut want2 = s(&[(1, 100_000), (200_001, 300_000), (400_001, 500_000)]);
        f(&mut a, &mut b1, &mut want1);
        f(&mut a, &mut b2, &mut want2);
    }

    // Port of Go TestUnmarshal.
    #[test]
    fn test_unmarshal() {
        let n = 100_000u64;
        let mut src = vec![0u8; ((n + 1) * 8) as usize + 10];
        src[..8].copy_from_slice(&n.to_be_bytes());
        let mut want = Set::default();
        for i in 0..n {
            let pos = ((i + 1) * 8) as usize;
            src[pos..pos + 8].copy_from_slice(&i.to_be_bytes());
            want.add(i);
        }

        let (got, got_tail) = match Set::unmarshal(&src) {
            Ok(v) => v,
            Err(err) => panic!("unexpected error: {err}"),
        };
        let mut got = got;
        assert!(
            got.equal(&want),
            "unexpected set; want {:?}; got {:?}",
            want.append_to(Vec::new()),
            got.append_to(Vec::new())
        );
        let want_tail = vec![0u8; 10];
        assert_eq!(want_tail.as_slice(), got_tail, "unexpected tail bytes");
    }

    // Port of Go TestUnmarshal_zeroLenSet.
    #[test]
    fn test_unmarshal_zero_len_set() {
        let src = vec![0u8; 8];
        let want = Set::default();
        let (got, got_tail) = match Set::unmarshal(&src) {
            Ok(v) => v,
            Err(err) => panic!("unexpected error: {err}"),
        };
        assert!(got.equal(&want), "unexpected set");
        let want_tail: &[u8] = &[];
        assert_eq!(want_tail, got_tail, "unexpected tail bytes");
    }

