    // Port of Go TestMarshal_nonEmptyDst.
    #[test]
    fn test_marshal_non_empty_dst() {
        let n = 100_000u64;
        let mut got = vec![0u8; 10];
        let mut want = vec![0u8; 10 + ((n + 1) * 8) as usize];
        for i in 0..10 {
            got[i] = i as u8;
            want[i] = i as u8;
        }
        want[10..18].copy_from_slice(&n.to_be_bytes());
        let mut s = Set::default();
        for i in 0..n {
            let pos = 10 + ((i + 1) * 8) as usize;
            want[pos..pos + 8].copy_from_slice(&i.to_be_bytes());
            s.add(i);
        }

        let got = s.marshal(got);
        assert_eq!(want, got, "unexpected bytes");
    }
